import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import logo from './logo.svg';
import './App.css';

// Navbar component
function Navbar() {
  const location = useLocation();
  const navItems = [
    { name: 'Home', path: '/' },
    { name: 'Generator', path: '/generator' },
    { name: 'Projects', path: '/projects' },
    { name: 'Docs', path: '/docs' },
    { name: 'Settings', path: '/settings' },
  ];
  return (
    <nav style={{ display: 'flex', alignItems: 'center', background: '#18181b', padding: '0.5rem 2rem', color: 'white' }}>
      <img src={logo} alt="logo" style={{ width: 32, height: 32, marginRight: 12 }} />
      <span style={{ fontWeight: 700, fontSize: 20, marginRight: 32, color: 'white' }}>CodeGen AI</span>
      {navItems.map(item => (
        <Link
          key={item.path}
          to={item.path}
          style={{
            color: location.pathname === item.path ? '#fff' : '#cbd5e1',
            background: location.pathname === item.path ? '#27272a' : 'transparent',
            borderRadius: 8,
            padding: '0.5rem 1rem',
            marginRight: 8,
            textDecoration: 'none',
            fontWeight: 500
          }}
        >
          {item.name}
        </Link>
      ))}
    </nav>
  );
}

// Placeholder pages
function Home() {
  return <div style={{ padding: '2rem' }}><h2>Welcome to CodeGen AI</h2><p>Generate code for your projects using AI.</p></div>;
}
function Generator() {
  const [prompt, setPrompt] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const handleSubmit = (e) => {
    e.preventDefault();
    setGeneratedCode(`// Code generated for prompt: "${prompt}"
console.log('Hello, world!');`);
  };
  return (
    <div style={{ padding: '2rem' }}>
      <h2>AI Code Generator</h2>
      <form onSubmit={handleSubmit} style={{ marginBottom: '1rem' }}>
        <input
          type="text"
          value={prompt}
          onChange={e => setPrompt(e.target.value)}
          placeholder="Describe your project..."
          style={{ width: '300px', padding: '0.5rem' }}
        />
        <button type="submit" style={{ marginLeft: '1rem', padding: '0.5rem 1rem' }}>
          Generate Code
        </button>
      </form>
      {generatedCode && (
        <div style={{ textAlign: 'left', background: '#222', padding: '1rem', borderRadius: '8px', maxWidth: '600px', margin: '0 auto' }}>
          <pre style={{ color: '#61dafb', whiteSpace: 'pre-wrap' }}>{generatedCode}</pre>
        </div>
      )}
    </div>
  );
}
function Projects() {
  return <div style={{ padding: '2rem' }}><h2>Projects</h2><p>View and manage your generated projects here.</p></div>;
}
function Docs() {
  return <div style={{ padding: '2rem' }}><h2>Docs</h2><p>Documentation and usage instructions.</p></div>;
}
function Settings() {
  return <div style={{ padding: '2rem' }}><h2>Settings</h2><p>Configure your preferences here.</p></div>;
}

function App() {
  return (
    <Router>
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/generator" element={<Generator />} />
        <Route path="/projects" element={<Projects />} />
        <Route path="/docs" element={<Docs />} />
        <Route path="/settings" element={<Settings />} />
      </Routes>
    </Router>
  );
}

export default App;
